import React from "react";
import { Blocks, Layers, Code, Palette, Shield, BarChart, Zap, Settings } from "lucide-react";
import { ListItem, NavigationMenu, NavigationMenuItem, NavigationMenuLink, NavigationMenuList, NavigationMenuContent, NavigationMenuTrigger, navigationMenuTriggerStyle } from "@/components/ui/navigation-menu";

const data = {
  "triggers": [
    {
      "label": "Getting started",
      "promo": {
        "icon": "Blocks",
        "title": "UI Components",
        "description": "Beautifully designed components built with Radix UI and Tailwind CSS."
      },
      "listItems": [
        {
          "href": "#",
          "title": "Introduction",
          "icon": "Layers",
          "description": "Re-usable components built using Radix UI and Tailwind CSS."
        },
        {
          "href": "#",
          "title": "Installation",
          "icon": "Code",
          "description": "How to install dependencies and structure your app."
        },
        {
          "href": "#",
          "title": "Typography",
          "icon": "Palette",
          "description": "Styles for headings, paragraphs, lists, and more."
        }
      ]
    },
    {
      "label": "Components",
      "listItems": [
        {
          "href": "#",
          "title": "Alert Dialog",
          "icon": "Shield",
          "description": "A modal dialog that interrupts the user with important content."
        },
        {
          "href": "#",
          "title": "Hover Card",
          "icon": "Layers",
          "description": "For sighted users to preview content behind a link."
        },
        {
          "href": "#",
          "title": "Progress",
          "icon": "BarChart",
          "description": "Displays an indicator showing completion progress."
        },
        {
          "href": "#",
          "title": "Scroll Area",
          "icon": "Zap",
          "description": "Visually or semantically separates content."
        },
        {
          "href": "#",
          "title": "Tabs",
          "icon": "Settings",
          "description": "A set of layered sections of content—known as tab panels."
        },
        {
          "href": "#",
          "title": "Tooltip",
          "icon": "Code",
          "description": "A popup that displays information related to an element."
        }
      ]
    }
  ],
  "simpleLink": {
    "label": "Documentation",
    "href": "#"
  }
};

const iconMap = { Blocks, Layers, Code, Palette, Shield, BarChart, Zap, Settings };

export default function NavigationMenuFullExample() {
  return (
    <NavigationMenu>
      <NavigationMenuList>
        {data.triggers.map((t) => (
          <NavigationMenuItem key={t.label}>
            {t.promo ? (
              <NavigationMenuTrigger>{t.label}</NavigationMenuTrigger>
            ) : (
              <NavigationMenuTrigger>{t.label}</NavigationMenuTrigger>
            )}
            <NavigationMenuContent>
              <ul className="grid gap-3 p-4 w-[400px] md:w-[500px] lg:w-[600px] lg:grid-cols-2">
                {t.promo && (
                  <li className="row-span-3">
                    <NavigationMenuLink asChild>
                      <a className="flex h-full w-full select-none flex-col justify-end rounded-md bg-gradient-to-b from-muted/50 to-muted p-6 no-underline" href="#">
                        <div className="mb-2 mt-4 text-lg font-medium">{t.promo.title}</div>
                        <p className="text-sm leading-tight text-muted-foreground">{t.promo.description}</p>
                      </a>
                    </NavigationMenuLink>
                  </li>
                )}
                {t.listItems?.map((item) => (
                  <ListItem key={item.title} href={item.href} title={item.title}>
                    {item.description}
                  </ListItem>
                ))}
              </ul>
            </NavigationMenuContent>
          </NavigationMenuItem>
        ))}
        <NavigationMenuItem>
          <NavigationMenuLink className={navigationMenuTriggerStyle()} href={data.simpleLink.href}>
            {data.simpleLink.label}
          </NavigationMenuLink>
        </NavigationMenuItem>
      </NavigationMenuList>
    </NavigationMenu>
  );
}
